import{_ as a,o as i,c as l,ai as s}from"./chunks/framework.C4ntERNc.js";const u=JSON.parse('{"title":"Module Structure","description":"","frontmatter":{"title":"Module Structure","lang":"en-US","layout":"doc","outline":"deep"},"headers":[],"relativePath":"reference-manual/formal-reference/module-structure.md","filePath":"reference-manual/formal-reference/module-structure.md"}'),t={name:"reference-manual/formal-reference/module-structure.md"};function n(o,e,d,c,r,p){return i(),l("div",null,[...e[0]||(e[0]=[s(`<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /jz-hdl/reference-manual/formal-reference/module-structure.md for this page in Markdown format</div><h1 id="module-structure" tabindex="-1">Module Structure <a class="header-anchor" href="#module-structure" aria-label="Permalink to “Module Structure”">​</a></h1><h2 id="canonical-form" tabindex="-1">Canonical form <a class="header-anchor" href="#canonical-form" aria-label="Permalink to “Canonical form”">​</a></h2><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>@module &lt;module_name&gt;</span></span>
<span class="line"><span>  CONST { ... }</span></span>
<span class="line"><span>  PORT { ... }</span></span>
<span class="line"><span>  WIRE { ... }</span></span>
<span class="line"><span>  REGISTER { ... }</span></span>
<span class="line"><span>  MEM(type=[BLOCK|DISTRIBUTED]) { ... }</span></span>
<span class="line"><span>  ASYNCHRONOUS { ... }</span></span>
<span class="line"><span>  SYNCHRONOUS(CLK=&lt;name&gt; ...) { ... }</span></span>
<span class="line"><span>@endmod</span></span></code></pre></div><p>Other declaration and logic blocks (<code>LATCH</code>, <code>MUX</code>, <code>CDC</code>, <code>@template</code>, <code>@feature</code>) may appear where declarations or statements are valid, per their sections below.</p><h2 id="scope-and-uniqueness" tabindex="-1">Scope and uniqueness <a class="header-anchor" href="#scope-and-uniqueness" aria-label="Permalink to “Scope and uniqueness”">​</a></h2><ul><li>Each module must declare at least one port.</li><li>Module and blackbox names are unique project-wide.</li><li>All identifiers within a module are unique (ports, wires, registers, constants, instances).</li><li><code>CONST</code> scope is module-local.</li><li>Instance names are unique in their parent module and cannot collide with other identifiers.</li></ul><h2 id="const" tabindex="-1">CONST <a class="header-anchor" href="#const" aria-label="Permalink to “CONST”">​</a></h2><ul><li>Syntax: <code>NAME = nonneg_integer;</code> (numeric) or <code>NAME = &quot;string&quot;;</code> (string)</li><li>Numeric constants are compile-time only; used in widths and indices.</li><li>String constants hold file paths; used in <code>@file()</code> path arguments.</li><li>Using a string CONST in a numeric context or vice versa is a compile error.</li><li>For runtime constants, use <code>@global</code> or <code>lit(width, value)</code>.</li></ul><h2 id="port" tabindex="-1">Port <a class="header-anchor" href="#port" aria-label="Permalink to “Port”">​</a></h2><ul><li><code>IN [N] name;</code>, <code>OUT [N] name;</code>, <code>INOUT [N] name;</code></li><li>Width is mandatory.</li><li><code>INOUT</code> supports tri-state by assigning <code>z</code>.</li><li>All ports must be listed in <code>@new</code> instantiations.</li></ul><h3 id="bus-ports" tabindex="-1">BUS Ports <a class="header-anchor" href="#bus-ports" aria-label="Permalink to “BUS Ports”">​</a></h3><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>PORT {</span></span>
<span class="line"><span>  BUS &lt;bus_id&gt; &lt;ROLE&gt; [&lt;count&gt;] &lt;bus_port_name&gt;;</span></span>
<span class="line"><span>}</span></span></code></pre></div><ul><li>ROLE is <code>SOURCE</code> or <code>TARGET</code>.</li><li>Directions are resolved from the BUS definition relative to SOURCE.</li><li>Access uses dot notation: <code>bus_port.signal</code>, <code>bus_port[i].signal</code>, or wildcard <code>bus_port[*].signal</code>.</li><li>Wildcard <code>[*]</code> fanout: <ul><li><strong>Broadcast</strong>: 1-bit RHS is replicated to all elements.</li><li><strong>Element-wise pairing</strong>: RHS width must equal element count; each bit drives one element.</li><li>Width mismatch (RHS width != 1 and != count) → compile error.</li></ul></li><li>All standard assignment operators apply; width rules and Exclusive Assignment Rule apply per signal.</li></ul><h2 id="wire" tabindex="-1">WIRE <a class="header-anchor" href="#wire" aria-label="Permalink to “WIRE”">​</a></h2><ul><li>Syntax: <code>name [width];</code></li><li>Combinational net written in <code>ASYNCHRONOUS</code> blocks only.</li></ul><h2 id="register" tabindex="-1">REGISTER <a class="header-anchor" href="#register" aria-label="Permalink to “REGISTER”">​</a></h2><ul><li>Syntax: <code>name [width] = literal;</code></li><li>Mandatory reset value; reset literal must not contain <code>x</code>.</li><li>Read anywhere; written only in <code>SYNCHRONOUS</code> blocks.</li></ul><h2 id="latch" tabindex="-1">LATCH <a class="header-anchor" href="#latch" aria-label="Permalink to “LATCH”">​</a></h2><p><strong>Syntax:</strong> <code>&lt;name&gt; [&lt;width&gt;] &lt;type&gt;;</code> where <code>&lt;type&gt;</code> is <code>D</code> or <code>SR</code>.</p><ul><li>Written only in <code>ASYNCHRONOUS</code> using guarded assignments: <ul><li>D latch: <code>latch_name &lt;= enable : data;</code> — enable must be width-1. When <code>1</code>, latch is transparent; when <code>0</code>, latch holds.</li><li>SR latch: <code>latch_name &lt;= set : reset;</code> — set and reset must be same width as latch.</li></ul></li><li>Level-sensitive storage; no clock domains; Exclusive Assignment Rule applies.</li><li>Reading a latch is passive and unconditional; readable in ASYNCHRONOUS and SYNCHRONOUS blocks.</li><li>Latches may not be used as a clock, reset, or CDC source.</li><li>Latches may not be aliased (<code>=</code>) to another net.</li><li>Latches may not be written in <code>SYNCHRONOUS</code> blocks.</li><li>SR latch truth table (per bit): set=1,reset=0 → 1; set=0,reset=1 → 0; set=0,reset=0 → hold; set=1,reset=1 → metastable.</li></ul><h2 id="mux" tabindex="-1">MUX <a class="header-anchor" href="#mux" aria-label="Permalink to “MUX”">​</a></h2><p>Two forms:</p><ul><li>Aggregation: <code>mux_name = source0, source1, ...;</code> (all sources same width)</li><li>Auto-slicing: <code>mux_name [element_width] = wide_source;</code> (wide source width is exact multiple)</li></ul><p><code>mux_id[sel]</code> is read-only.</p><h3 id="selector-width-and-out-of-range-behavior" tabindex="-1">Selector width and out-of-range behavior <a class="header-anchor" href="#selector-width-and-out-of-range-behavior" aria-label="Permalink to “Selector width and out-of-range behavior”">​</a></h3><ul><li>Selector width should be &gt;= <code>clog2(N)</code> where N is the number of MUX elements.</li><li>If the selector is narrower than <code>clog2(N)</code>, it is implicitly zero-extended.</li><li>If the compiler can statically prove that the selector value is out of range (&gt;= N), it is a <strong>compile error</strong>.</li><li>If the selector may be out of range at runtime, the result is <strong>all zeros</strong>.</li></ul><h2 id="mem" tabindex="-1">MEM <a class="header-anchor" href="#mem" aria-label="Permalink to “MEM”">​</a></h2><ul><li>Declared in <code>MEM(type=[BLOCK|DISTRIBUTED]) { ... }</code>.</li><li>Full semantics are defined in the Memory section.</li></ul><h2 id="asynchronous-block" tabindex="-1">ASYNCHRONOUS block <a class="header-anchor" href="#asynchronous-block" aria-label="Permalink to “ASYNCHRONOUS block”">​</a></h2><ul><li>Combinational logic with assignments, conditionals, and SELECT/CASE.</li><li>Alias operators (<code>=</code>/<code>=z</code>/<code>=s</code>) are unconditional only and cannot appear inside conditional control flow.</li><li>Bare literal RHS is forbidden with alias operators.</li><li>Tri-state allowed via <code>z</code>.</li></ul><h2 id="synchronous-block" tabindex="-1">SYNCHRONOUS block <a class="header-anchor" href="#synchronous-block" aria-label="Permalink to “SYNCHRONOUS block”">​</a></h2><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>SYNCHRONOUS(</span></span>
<span class="line"><span>  CLK=&lt;name&gt;</span></span>
<span class="line"><span>  EDGE=[Rising|Falling|Both]</span></span>
<span class="line"><span>  RESET=&lt;name&gt;</span></span>
<span class="line"><span>  RESET_ACTIVE=[High|Low]</span></span>
<span class="line"><span>  RESET_TYPE=[Immediate|Clocked]</span></span>
<span class="line"><span>) { ... }</span></span></code></pre></div><ul><li>At most one <code>SYNCHRONOUS</code> block per unique clock.</li><li><code>EDGE=Both</code> generates dual-edge-triggered logic; not a standard FPGA primitive — compiler emits a warning.</li><li>Registers are bound to their first assignment clock domain.</li><li>Reset has highest priority; Immediate reset is combinational (compiler generates an async-assert/sync-deassert reset synchronizer), Clocked reset is edge-triggered.</li><li>Only directional operators (<code>&lt;=</code>, <code>=&gt;</code> and modifiers) are allowed. Alias (<code>=</code>) is forbidden.</li></ul><h2 id="cdc-block" tabindex="-1">CDC block <a class="header-anchor" href="#cdc-block" aria-label="Permalink to “CDC block”">​</a></h2><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>CDC {</span></span>
<span class="line"><span>  &lt;type&gt;[n_stages] &lt;source_reg&gt; (&lt;src_clk&gt;) =&gt; &lt;dest_alias&gt; (&lt;dest_clk&gt;);</span></span>
<span class="line"><span>}</span></span></code></pre></div><ul><li>Types: <code>BIT</code>, <code>BUS</code>, <code>FIFO</code>, <code>HANDSHAKE</code>, <code>PULSE</code>, <code>MCP</code>, <code>RAW</code>.</li><li>Creates a read-only alias in the destination domain.</li><li>Source register must be a plain register identifier; CDC sets its home domain.</li></ul><h2 id="module-instantiation-new" tabindex="-1">Module instantiation (<code>@new</code>) <a class="header-anchor" href="#module-instantiation-new" aria-label="Permalink to “Module instantiation (@new)”">​</a></h2><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>@new &lt;instance_name&gt; &lt;module_name&gt; {</span></span>
<span class="line"><span>  OVERRIDE { &lt;child_const_id&gt; = &lt;expr&gt;; }</span></span>
<span class="line"><span>  IN/OUT/INOUT/BUS ... = &lt;parent_signal_or_literal&gt;;</span></span>
<span class="line"><span>}</span></span></code></pre></div><ul><li>All child ports must be listed.</li><li>Widths in <code>@new</code> are evaluated in the parent scope (CONST/CONFIG).</li><li><code>_</code> may be used as a no-connect placeholder.</li><li>Assigning a parent signal to a child OUT counts as a driver in the parent (Exclusive Assignment Rule).</li><li>BUS bindings must match the child BUS port&#39;s bus_id, role, and array count (if any).</li></ul><h3 id="array-instantiation" tabindex="-1">Array instantiation <a class="header-anchor" href="#array-instantiation" aria-label="Permalink to “Array instantiation”">​</a></h3><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>@new &lt;instance_name&gt;[&lt;count&gt;] &lt;module_name&gt; { ... }</span></span></code></pre></div><ul><li>The count is a positive integer or parent <code>CONST</code>.</li><li><code>IDX</code> is available only in parent-side expressions in the array mapping. <code>IDX</code> is not a first-class value and cannot be assigned, compared, or stored.</li><li><code>IDX</code> is prohibited inside <code>OVERRIDE</code>.</li><li>Non-overlap rule: per-instance OUT mappings must not drive overlapping parent bits.</li><li>Only single-dimensional instance arrays are supported.</li><li>Arrayed instance ports can be referenced as <code>instance_name[index].port_name</code> in ASYNCHRONOUS/SYNCHRONOUS blocks.</li></ul><h2 id="templates" tabindex="-1">Templates <a class="header-anchor" href="#templates" aria-label="Permalink to “Templates”">​</a></h2><ul><li>Defined with <code>@template &lt;name&gt; (&lt;params&gt;) ... @endtemplate</code>.</li><li>Placement: module-scoped (inside <code>@module</code>) or file-scoped (outside <code>@module</code>/<code>@project</code>).</li><li>Applied with <code>@apply &lt;name&gt; (&lt;args&gt;);</code> or <code>@apply [count] &lt;name&gt; (&lt;args&gt;);</code> inside <code>ASYNCHRONOUS</code> or <code>SYNCHRONOUS</code> bodies.</li><li>Templates may contain only: assignments (<code>&lt;=</code>, <code>=&gt;</code>, <code>=</code> and modifiers), conditionals (<code>IF</code>/<code>SELECT</code>), expressions, and scratch wires (<code>@scratch</code>).</li><li>Templates may <strong>not</strong> contain: <code>WIRE</code>, <code>REGISTER</code>, <code>PORT</code>, <code>CONST</code>, <code>MEM</code>, <code>MUX</code>, <code>@new</code>, <code>CDC</code>, <code>@feature</code>, nested <code>@template</code>, or block headers.</li><li>All identifiers must be parameters or scratch wires; no external references allowed.</li><li><code>@apply [count]</code> unrolls the template <code>count</code> times with <code>IDX</code> substituted as a compile-time literal (0 to count-1).</li><li><code>IDX</code> is compile-time only; using it as a runtime value is a compile error.</li><li>After expansion, all normal semantic rules apply (Exclusive Assignment, widths, uniqueness).</li><li>Full details in the <a href="/jz-hdl/reference-manual/formal-reference/templates.html">Templates</a> reference.</li></ul><h2 id="feature-guards" tabindex="-1">Feature guards <a class="header-anchor" href="#feature-guards" aria-label="Permalink to “Feature guards”">​</a></h2><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>@feature &lt;config_expr&gt;</span></span>
<span class="line"><span>  ...</span></span>
<span class="line"><span>@else</span></span>
<span class="line"><span>  ...</span></span>
<span class="line"><span>@endfeat</span></span></code></pre></div><ul><li>May appear anywhere a declaration or statement is valid.</li><li><code>config_expr</code> is compile-time, width-1, and may only reference <code>CONFIG</code>, <code>CONST</code>, literals, and logical operators (<code>&amp;&amp;</code>, <code>||</code>, <code>!</code>, <code>==</code>, <code>!=</code>, <code>&lt;</code>, <code>&gt;</code>, <code>&lt;=</code>, <code>&gt;=</code>).</li><li><code>@feature</code> blocks may <strong>not</strong> be nested.</li><li>The block does not create a new scope; identifiers declared inside <code>@feature</code> are visible to the entire module.</li><li>Both enabled and disabled variants must be semantically valid.</li></ul>`,48)])])}const m=a(t,[["render",n]]);export{u as __pageData,m as default};
